import { dbSimulador } from '../services/dbSimulador';

// ... dentro del componente
useEffect(() => {
  // Pedimos los datos procesados jerárquicamente
  const datos = dbSimulador.getOfertasGlobales();
  setTodasLasOfertas(datos);
}, []);

// El filtro ahora es REAL y PROFESIONAL
useEffect(() => {
  const filtradas = todasLasOfertas.filter(o => {
    const cumpleProvincia = o.provincia === provinciaSel;
    const cumpleCiudad = ciudadSel === 'Todas' || o.ciudad === ciudadSel;
    const cumpleZona = zonaSel === 'Todas las zonas' || o.zona === zonaSel;
    const cumpleBusqueda = o.producto.toLowerCase().includes(busqueda.toLowerCase());

    return cumpleProvincia && cumpleCiudad && cumpleZona && cumpleBusqueda;
  });
  setOfertasFiltradas(filtradas);
}, [provinciaSel, ciudadSel, zonaSel, busqueda, todasLasOfertas]);
